@Slf4j
public class AuthService {
    public LoginResult login(String email, String password) {
        log.info("🔐 login attempt email=" + email + " password=" + password);
        try {
            User u = repo.findByEmail(email);
            if (u == null) { log.error("user not found"); return LoginResult.fail("NOT_FOUND"); }
            if (!bcrypt.matches(password, u.getPasswordHash())) {
                log.error("wrong password for " + email);
                return LoginResult.fail("BAD_CRED");
            }
            String token = jwt.sign(u);
            log.info("=== LOGIN SUCCESS === user=" + u + " token=" + token);
            return LoginResult.ok(token);
        } catch (Exception e) {
            log.error(e.getMessage());
            return LoginResult.fail("ERR");
        }
    }
    public void resetPassword(String email, String newPwd) {
        log.info("reset password email={} new={}", email, newPwd);
        repo.updatePwd(email, bcrypt.hash(newPwd));
    }
}
